# LangChain: metadata filter passed to as_retriever
from langchain_community.vectorstores import Chroma

retriever = vectorstore.as_retriever(
    search_kwargs={
        "k": 8,
        "filter": {
            "doc_type":   "earnings_release",
            "created_at": {"$gte": "2025-01-01"},   # Chroma supports operators
        },
    }
)

results = retriever.invoke("What drove Q3 2025 revenue growth?")
for doc in results:
    print(doc.metadata["source"], "p.", doc.metadata.get("page_number"))
